# Regex to validate extension name format (alphanumeric, underscores, hyphens)
EXTENSION_NAME_PATTERN = re.compile(r'^[a-zA-Z][a-zA-Z0-9_\-]*$')


def validate_extension_name(extension_name: str) -> tuple[bool, str]:
    """Validate the extension name against whitelist and format rules."""
    if not extension_name:
        return False, "Extension name cannot be empty."

    extension_name = extension_name.strip().lower()

    if not EXTENSION_NAME_PATTERN.match(extension_name):
        return False, (
            f"Invalid extension name format: '{extension_name}'. "
            "Extension names must start with a letter and contain only "
            "alphanumeric characters, underscores, or hyphens."
        )

    if extension_name not in ALLOWED_EXTENSIONS:
        return False, (
            f"Extension '{extension_name}' is not in the allowed extensions list. "
            "Contact your administrator to add it to the whitelist."
        )

    return True, extension_name


def get_db_connection(host: str, port: str, dbname: str, user: str, password: str):
    """Create and return a database connection."""
    conn = psycopg2.connect(
        host=host,
        port=port,
        dbname=dbname,
        user=user,
        password=password,
    )
    conn.autocommit = True
    return conn


def list_installed_extensions(conn) -> list[dict]:
    """List all currently installed extensions."""
    with conn.cursor() as cur:
        cur.execute("SELECT extname, extversion FROM pg_extension ORDER BY extname;")
        rows = cur.fetchall()
    return [{"name": row[0], "version": row[1]} for row in rows]


def list_available_extensions(conn) -> list[dict]:
    """List all available extensions that can be installed."""
    with conn.cursor() as cur:
        cur.execute(
            "SELECT name, default_version, comment "
            "FROM pg_available_extensions ORDER BY name;"
        )
        rows = cur.fetchall()
    return [{"name": row[0], "version": row[1], "comment": row[2]} for row in rows]


def install_extension(conn, extension_name: str, if_not_exists: bool = True) -> tuple[bool, str]:
    """
    Install a PostgreSQL extension safely using parameterized identifiers.

    Uses psycopg2.sql module to safely compose the query with proper
    identifier quoting, preventing SQL injection.
    """
    is_valid, result = validate_extension_name(extension_name)
    if not is_valid:
        return False, result

    sanitized_name = result

    try:
        with conn.cursor() as cur:
            if if_not_exists:
                query = psycopg2.sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )
            else:
                query = psycopg2.sql.SQL("CREATE EXTENSION {}").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )

            cur.execute(query)

        return True, f"Extension '{sanitized_name}' installed successfully."

    except psycopg2.errors.DuplicateObject:
        return False, f"Extension '{sanitized_name}' is already installed."
    except psycopg2.errors.InsufficientPrivilege:
        return False, (
            f"Insufficient privileges to install extension '{sanitized_name}'. "
            "Superuser or appropriate permissions required."
        )
    except psycopg2.errors.UndefinedFile:
        return False, (
            f"Extension '{sanitized_name}' is not available on this server. "
            "The extension package may need to be installed on the OS level."
        )
    except psycopg2.Error as e:
        return False, f"Database error installing '{sanitized_name}': {e}"


def uninstall_extension(conn, extension_name: str, cascade: bool = False) -> tuple[bool, str]:
    """Uninstall a PostgreSQL extension safely."""
    is_valid, result = validate_extension_name(extension_name)
    if not is_valid:
        return False, result

    sanitized_name = result

    try:
        with conn.cursor() as cur:
            if cascade:
                query = psycopg2.sql.SQL("DROP EXTENSION IF EXISTS {} CASCADE").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )
            else:
                query = psycopg2.sql.SQL("DROP EXTENSION IF EXISTS {}").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )

            cur.execute(query)

        return True, f"Extension '{sanitized_name}' uninstalled successfully."

    except psycopg2.errors.DependentObjectsStillExist:
        return False, (
            f"Extension '{sanitized_name}' has dependent objects. "
            "Use cascade option to force removal."
        )
    except psycopg2.errors.InsufficientPrivilege:
        return False, f"Insufficient privileges to uninstall extension '{sanitized_name}'."
    except psycopg2.Error as e:
        return False, f"Database error uninstalling '{sanitized_name}': {e}"


def print_extensions_table(extensions: list[dict], title: str):
    """Pretty print extensions in a table format."""
    print(f"\n{'=' * 60}")
    print(f"  {title}")
    print(f"{'=' * 60}")
    if not extensions:
        print("  No extensions found.")
    else:
        for ext in extensions:
            version = ext.get("version", "N/A")
            comment = ext.get("comment", "")
            line = f"  {ext['name']:<30} v{version}"
            if comment:
                line += f"  - {comment[:50]}"
            print(line)
    print(f"{'=' * 60}\n")


